SELECT airline_name, headquarters, COUNT(*) OVER (PARTITION BY headquarters) AS same_city_airlines_count
FROM airlines
ORDER BY headquarters;

SELECT user_id, rating
FROM flight_ratings
WHERE rating_date >= '2023-01-01';

SELECT AVG(bookings_per_flight) AS average_bookings_per_flight
FROM (
    SELECT COUNT(*) AS bookings_per_flight
    FROM bookings
    GROUP BY flight_id
);
